// Trusted, public health / pandemic RSS sources (real article URLs + real
// article photos via og:image). Add more health feeds freely.
return [
  { json: { url: 'https://www.who.int/rss-feeds/news-english.xml' } },
  { json: { url: 'https://news.un.org/feed/subscribe/en/news/topic/health/feed/rss.xml' } }
];

// Normalize + enrich: for each article fetch its page and read og:image so the
// card shows the real photo. source_name is derived from the link domain.
// Only items with a real photo are kept. Runs once for all items (async).
function srcOf(link){
  if (link.includes('who.int')) return 'World Health Organization';
  if (link.includes('news.un.org')) return 'UN News';
  if (link.includes('cdc.gov')) return 'US CDC';
  if (link.includes('channelnewsasia')) return 'CNA';
  if (link.includes('straitstimes')) return 'The Straits Times';
  try { return new URL(link).hostname.replace(/^www\./, ''); } catch (e) { return 'Health News'; }
}
function safeISO(v){ const t = v ? Date.parse(v) : NaN; return Number.isNaN(t) ? null : new Date(t).toISOString(); }
const rows = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const link = j.link || j.guid;
  const title = (j.title || '').trim();
  if (!link || !title) continue;
  let image = null;
  try {
    const html = await this.helpers.httpRequest({ url: link, headers: { 'User-Agent': 'Mozilla/5.0' }, timeout: 12000 });
    const m = String(html).match(/property=["']og:image["'][^>]+content=["']([^"']+)/i)
          || String(html).match(/name=["']twitter:image["'][^>]+content=["']([^"']+)/i);
    if (m) image = m[1];
  } catch (e) {}
  if (!image) continue; // keep only items with a real photo
  rows.push({
    title: title.slice(0, 300),
    summary: (j.contentSnippet || j.summary || '').replace(/<[^>]+>/g, '').trim().slice(0, 300) || null,
    source_name: srcOf(link),
    source_url: link,
    category: 'Public Health',
    location: 'Global',
    severity: null,
    image_url: image,
    published_at: safeISO(j.isoDate || j.pubDate)
  });
}
return rows.map((r) => ({ json: r }));

// De-dupe by source_url and emit a single array so the upsert is one request.
const seen = new Set();
const rows = [];
for (const item of $input.all()) {
  const r = item.json;
  if (!r || !r.source_url || seen.has(r.source_url)) continue;
  seen.add(r.source_url);
  rows.push(r);
}
return [{ json: { rows: rows.slice(0, 15) } }];
